prompt:
Add flake.nix to reel-life for Nix-native building and deployment as a NixOS service.

## Context
reel-life is a Go application (Go 1.24) that will be deployed on a NixOS host (classic-laddie) as a systemd service. It needs a flake.nix that builds the binary and exports a NixOS module.

## What to build

### 1. flake.nix

Create a flake with:

**Inputs:**
- nixpkgs (nixos-unstable)

**Outputs:**

a) **packages.default** — build the Go binary with `buildGoModule`:
```nix
buildGoModule {
  pname = "reel-life";
  src = ./.;
  vendorHash = "...";  # run nix build and get the right hash
  subPackages = [ "cmd/reel-life" ];
}
```
Run `nix build` to get the correct vendorHash — it will fail the first time and tell you the expected hash.

b) **devShells.default** — dev shell with go, gopls, golangci-lint, gh, git

c) **nixosModules.default** — a NixOS module (see below)

d) **overlays.default** — overlay that adds reel-life to pkgs

### 2. NixOS Module

Create `nix/module.nix` (imported by the flake's nixosModules output):

```nix
{ config, lib, pkgs, ... }:
let
  cfg = config.services.reel-life;
in {
  options.services.reel-life = {
    enable = lib.mkEnableOption "reel-life media chatops agent";

    package = lib.mkOption {
      type = lib.types.package;
      default = pkgs.reel-life;
      description = "The reel-life package to use";
    };

    sonarrUrl = lib.mkOption {
      type = lib.types.str;
      default = "http://localhost:8989";
      description = "Sonarr base URL";
    };

    chatBackend = lib.mkOption {
      type = lib.types.str;
      default = "googlechat";
    };

    agentModel = lib.mkOption {
      type = lib.types.str;
      default = "claude-sonnet-4-5-20250929";
    };

    agentMaxTokens = lib.mkOption {
      type = lib.types.int;
      default = 4096;
    };

    monitorEnabled = lib.mkOption {
      type = lib.types.bool;
      default = true;
    };

    monitorInterval = lib.mkOption {
      type = lib.types.str;
      default = "5m";
    };

    logLevel = lib.mkOption {
      type = lib.types.str;
      default = "info";
    };

    logFormat = lib.mkOption {
      type = lib.types.str;
      default = "text";
    };

    environmentFiles = lib.mkOption {
      type = lib.types.listOf lib.types.path;
      default = [];
      description = "Files containing environment variables (for secrets like API keys)";
    };
  };

  config = lib.mkIf cfg.enable {
    # Generate config.yaml from module options
    environment.etc."reel-life/config.yaml".text = ''
      sonarr:
        base_url: ${cfg.sonarrUrl}
      chat:
        backend: ${cfg.chatBackend}
      agent:
        model: ${cfg.agentModel}
        max_tokens: ${toString cfg.agentMaxTokens}
      monitor:
        enabled: ${lib.boolToString cfg.monitorEnabled}
        interval: ${cfg.monitorInterval}
      log:
        level: ${cfg.logLevel}
        format: ${cfg.logFormat}
    '';

    systemd.services.reel-life = {
      description = "reel-life media chatops agent";
      after = [ "network-online.target" ];
      wants = [ "network-online.target" ];
      wantedBy = [ "multi-user.target" ];

      serviceConfig = {
        Type = "simple";
        ExecStart = "${cfg.package}/bin/reel-life -config /etc/reel-life/config.yaml";
        Restart = "on-failure";
        RestartSec = 10;

        # Security hardening
        DynamicUser = true;
        NoNewPrivileges = true;
        ProtectSystem = "strict";
        ProtectHome = true;
        PrivateTmp = true;
        PrivateDevices = true;
        ProtectKernelTunables = true;
        ProtectControlGroups = true;
        RestrictSUIDSGID = true;

        # Secrets via environment files (agenix paths)
        EnvironmentFile = cfg.environmentFiles;
      };
    };
  };
}
```

### 3. Important details

- The Go module path is in go.mod — read it to get the correct module name
- Run `nix build` to verify the build works and get the correct vendorHash
- Run `nix flake check` to validate
- The NixOS module should be self-contained so consuming flakes just add the input and import the module
- Read CLAUDE.md for project conventions
- Make sure existing tests still pass: `nix develop -c go test ./...`
